+        // Find closest mapping <= zig_line
+        var best: ?CodeMapping = null;
+        for (di.mappings) |m| {
+            if (m.zig_line <= zig_line) {
+                if (best == null or m.zig_line > best.?.zig_line) {
+                    best = m;
+                }
+            }
