+/// Compute hash of source content for invalidation
+fn computeHash(content: []const u8) u64 {
+    // FNV-1a hash
+    var hash: u64 = 0xcbf29ce484222325;
+    for (content) |byte| {
+        hash ^= byte;
+        hash *%= 0x100000001b3;
+    }
+    return hash;
+}
